// перейменовуємо бінарне вкладення на .zip (змінюємо лише метадані,
// самі байти файлу не чіпаємо).
const item = $input.item;
const bin = item.binary && item.binary.data;
if (bin) {
 const base = (bin.fileName || "file").replace(/\.[^.]+$/, "");
 bin.fileName = base + ".zip";
 bin.fileExtension = "zip";
 bin.mimeType = "application/zip";
}
return item;"

