// і віддаємо далі як бінарне поле "data".
const item = $input.item;
const binary = item.binary || {};
let picked = null;
for (const key of Object.keys(binary)) {
 const f = binary[key];
 const name = f.fileName || "";
 const isDoc = name === "word/document.xml" || name.endsWith("/document.xml") || name === "document.xml";
 if (isDoc && !name.includes(".rels")) { picked = f; break; }
}
if (!picked) throw new Error("document.xml не знайдено у розпакованому DOCX");
return { json: { picked: "word/document.xml" }, binary: { data: picked } };"

